// Daten aus allen Quellen sammeln
const trends = $('Fetch Trend Comparison').all().map(i => i.json);
const topics = $('Fetch Top Topics').all().map(i => i.json);
const intents = $('Fetch Intent Distribution').all().map(i => i.json);
const abandoned = $('Fetch Abandoned Sessions').first()?.json || {};
const feedback = $('Fetch Feedback Score').first()?.json || {};
const funnel = $('Fetch Lead Funnel').all().map(i => i.json);
const products = $('Fetch Product Interest').all().map(i => i.json);

// Datum formatieren
const now = new Date();
const weekStart = new Date(now - 7 * 24 * 60 * 60 * 1000);
const formatDate = (d) => d.toLocaleDateString('de-AT', { day: '2-digit', month: '2-digit', year: 'numeric' });
const dateRange = formatDate(weekStart) + ' - ' + formatDate(now);

// Trend-Daten formatieren
const trendMap = {};
trends.forEach(t => { trendMap[t.metric] = t; });

const formatChange = (pct) => {
  if (pct === null || pct === undefined) return 'N/A';
  const sign = pct >= 0 ? '+' : '';
  return sign + pct + '%';
};

// Top Topics formatieren (max 10)
const topTopicsText = topics.slice(0, 10)
  .map((t, i) => (i + 1) + '. ' + t.word + ' (' + t.mentions + 'x, ' + t.unique_sessions + ' Sessions)')
  .join('\n') || 'Keine Daten';

// Intent-Verteilung formatieren
const intentText = intents
  .map(i => '  - ' + i.intent + ': ' + i.count + ' (' + i.percentage + '%)')
  .join('\n') || 'Keine Daten';

// Lead Funnel formatieren
const funnelText = funnel
  .map(f => '  Schritt ' + f.step + ' (' + f.step_name + '): ' + f.sessions_at_step + ' Sessions (' + f.percentage + '%)')
  .join('\n') || 'Keine Daten';

// Produkt-Interesse formatieren
const productText = products
  .map(p => '  - ' + p.product + ': ' + p.lead_count + ' Leads (High: ' + p.high_urgency + ', Medium: ' + p.medium_urgency + ', Low: ' + p.low_urgency + ')')
  .join('\n') || 'Keine Daten';

// Email-Body zusammenbauen
const body = `
================================================================================
ROLLOMAX CHATBOT - WOECHENTLICHER MARKETING-REPORT
${dateRange}
================================================================================

1. TREND-VERGLEICH (Diese Woche vs. Letzte Woche)
--------------------------------------------------------------------------------
  Sessions:      ${trendMap.sessions?.this_week || 0} (Vorwoche: ${trendMap.sessions?.last_week || 0}) ${formatChange(trendMap.sessions?.change_pct)}
  Leads:         ${trendMap.leads?.this_week || 0} (Vorwoche: ${trendMap.leads?.last_week || 0}) ${formatChange(trendMap.leads?.change_pct)}
  Conversions:   ${trendMap.conversions?.this_week || 0} (Vorwoche: ${trendMap.conversions?.last_week || 0}) ${formatChange(trendMap.conversions?.change_pct)}
  Avg Messages:  ${trendMap.avg_messages?.this_week || 0} (Vorwoche: ${trendMap.avg_messages?.last_week || 0}) ${formatChange(trendMap.avg_messages?.change_pct)}

2. TOP 10 THEMEN/KEYWORDS
--------------------------------------------------------------------------------
${topTopicsText}

3. INTENT-VERTEILUNG
--------------------------------------------------------------------------------
${intentText}

4. ABBRUCH-ANALYSE
--------------------------------------------------------------------------------
  Abgebrochene Sessions (<3 Nachrichten, kein Lead): ${abandoned.abandoned_count || 0}
  Abbruch-Rate: ${abandoned.abandonment_rate_pct || 0}%

5. FEEDBACK & ZUFRIEDENHEIT
--------------------------------------------------------------------------------
  Gesamt-Feedback: ${feedback.total_feedback || 0} Bewertungen
  Positiv (Daumen hoch): ${feedback.positive || 0}
  Negativ (Daumen runter): ${feedback.negative || 0}
  Zufriedenheitsrate: ${feedback.satisfaction_rate_pct || 'N/A'}%
  Durchschnittliche Sterne: ${feedback.avg_star_rating || 'N/A'}/5

6. LEAD-ERFASSUNGS-FUNNEL
--------------------------------------------------------------------------------
${funnelText}

7. PRODUKT-INTERESSE
--------------------------------------------------------------------------------
${productText}

================================================================================
VERBESSERUNGSPOTENZIALE
================================================================================

${abandoned.abandonment_rate_pct > 50 ? '! ACHTUNG: Hohe Abbruch-Rate (' + abandoned.abandonment_rate_pct + '%). Pruefen Sie die Einstiegsnachrichten und Quick-Reply Buttons.' : ''}
${feedback.satisfaction_rate_pct < 70 ? '! ACHTUNG: Niedrige Zufriedenheit (' + feedback.satisfaction_rate_pct + '%). Pruefen Sie negative Feedback-Kommentare.' : ''}
${trendMap.leads?.change_pct < -20 ? '! ACHTUNG: Lead-Rueckgang (' + trendMap.leads.change_pct + '%). Analysieren Sie den Funnel auf Blockaden.' : ''}

Basierend auf den Top-Themen sollten Sie pruefen:
- Sind die haeufigsten Fragen gut in der Knowledge Base beantwortet?
- Gibt es wiederkehrende Themen, die auf der Website prominenter platziert werden sollten?
- Welche Produkte werden am meisten angefragt - stimmt das Angebot?

================================================================================
Dieser Report wurde automatisch generiert.
Bei Fragen wenden Sie sich an Ihren Chatbot-Administrator.
================================================================================
`.trim();

const subject = 'RolloMax Chatbot Wochenreport ' + dateRange;

return [{ json: { subject, body, dateRange } }];
